A clean, dark-themed admin panel. Design matches the site (#0F2438 bg, #FFD400 accent).

```tsx
import { useState, useEffect } from "react";
import { Shield, LogOut, Power, AlertTriangle, CheckCircle, Loader2, Eye, EyeOff } from "lucide-react";

// ── Login Form ────────────────────────────────────────────────────────────────
function LoginForm({ onLogin }: { onLogin: () => void }) {
  const [password, setPassword] = useState("");
  const [showPw, setShowPw] = useState(false);
  const [error, setError] = useState("");
  const [loading, setLoading] = useState(false);

  async function handleSubmit(e: React.FormEvent) {
    e.preventDefault();
    setError("");
    setLoading(true);
    try {
      const res = await fetch("/api/admin/login", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ password }),
        credentials: "include",
      });
      if (res.ok) {
        onLogin();
      } else {
        const data = await res.json();
        setError(data.error ?? "Contraseña incorrecta");
      }
    } catch {
      setError("Error de conexión");
    } finally {
      setLoading(false);
    }
  }

  return (
    <div className="min-h-screen bg-[#0F2438] flex items-center justify-center p-4">
      <div className="w-full max-w-sm">
        <div className="flex flex-col items-center mb-8 gap-3">
          <div className="w-16 h-16 rounded-full bg-[#FFD400]/10 border border-[#FFD400]/30 flex items-center justify-center">
            <Shield className="w-8 h-8 text-[#FFD400]" />
          </div>
          <h1 className="text-xl font-black text-white">Panel de Administración</h1>
          <p className="text-slate-400 text-sm">techbyflo.com</p>
        </div>

        <form onSubmit={handleSubmit} className="space-y-4">
          <div className="relative">
            <input
              type={showPw ? "text" : "password"}
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              placeholder="Contraseña de administrador"
              className="w-full bg-slate-800/60 border border-slate-700 rounded-xl px-4 py-3 text-white placeholder-slate-500 focus:outline-none focus:border-[#FFD400]/50 pr-12"
              required
              autoFocus
            />
            <button
              type="button"
              onClick={() => setShowPw(!showPw)}
              className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-400 hover:text-white"
            >
              {showPw ? <EyeOff className="w-4 h-4" /> : <Eye className="w-4 h-4" />}
            </button>
          </div>

          {error && (
            <div className="flex items-center gap-2 text-red-400 text-sm bg-red-400/10 border border-red-400/20 rounded-lg px-3 py-2">
              <AlertTriangle className="w-4 h-4 flex-shrink-0" />
              {error}
            </div>
          )}

          <button
            type="submit"
            disabled={loading || !password}
            className="w-full bg-[#FFD400] hover:bg-[#FFE033] disabled:opacity-50 text-[#0F2438] font-black py-3 px-6 rounded-xl transition-all flex items-center justify-center gap-2"
          >
            {loading ? <Loader2 className="w-4 h-4 animate-spin" /> : "Entrar"}
          </button>
        </form>
      </div>
    </div>
  );
}

// ── Dashboard ─────────────────────────────────────────────────────────────────
function Dashboard({ onLogout }: { onLogout: () => void }) {
  const [maintenance, setMaintenance] = useState<boolean | null>(null);
  const [loading, setLoading] = useState(false);
  const [message, setMessage] = useState<{ type: "ok" | "err"; text: string } | null>(null);

  useEffect(() => {
    fetch("/api/admin/maintenance", { credentials: "include" })
      .then((r) => r.json())
      .then((d) => setMaintenance(d.maintenance ?? false))
      .catch(() => setMaintenance(false));
  }, []);

  async function toggle() {
    if (maintenance === null) return;
    setLoading(true);
    setMessage(null);
    try {
      const res = await fetch("/api/admin/maintenance", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ enabled: !maintenance }),
        credentials: "include",
      });
      if (res.ok) {
        const data = await res.json();
        setMaintenance(data.maintenance);
        setMessage({ type: "ok", text: data.maintenance ? "Modo mantenimiento activado" : "Sitio en línea" });
      } else {
        setMessage({ type: "err", text: "Error al cambiar el estado" });
      }
    } catch {
      setMessage({ type: "err", text: "Error de conexión" });
    } finally {
      setLoading(false);
    }
  }

  async function handleLogout() {
    await fetch("/api/admin/logout", { method: "POST", credentials: "include" });
    onLogout();
  }

  return (
    <div className="min-h-screen bg-[#0F2438] flex items-center justify-center p-4">
      <div className="w-full max-w-md">
        {/* Header */}
        <div className="flex items-center justify-between mb-8">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 rounded-full bg-[#FFD400]/10 border border-[#FFD400]/30 flex items-center justify-center">
              <Shield className="w-5 h-5 text-[#FFD400]" />
            </div>
            <div>
              <h1 className="text-white font-black text-lg">Panel Admin</h1>
              <p className="text-slate-500 text-xs">techbyflo.com</p>
            </div>
          </div>
          <button
            onClick={handleLogout}
            className="flex items-center gap-1.5 text-slate-400 hover:text-white text-sm transition-colors"
          >
            <LogOut className="w-4 h-4" />
            Salir
          </button>
        </div>

        {/* Maintenance Toggle Card */}
        <div className="bg-slate-800/40 border border-slate-700 rounded-2xl p-6 space-y-5">
          <div className="flex items-center justify-between">
            <div>
              <h2 className="text-white font-bold text-base">Modo Mantenimiento</h2>
              <p className="text-slate-400 text-sm mt-0.5">
                {maintenance === null
                  ? "Cargando..."
                  : maintenance
                  ? "⚠️ El sitio está en mantenimiento"
                  : "✅ El sitio está en línea"}
              </p>
            </div>
            {/* Toggle switch */}
            <button
              onClick={toggle}
              disabled={loading || maintenance === null}
              className={`relative w-14 h-7 rounded-full transition-colors duration-300 focus:outline-none disabled:opacity-50 ${
                maintenance ? "bg-red-500" : "bg-slate-600"
              }`}
            >
              <span
                className={`absolute top-0.5 left-0.5 w-6 h-6 bg-white rounded-full shadow-md transition-transform duration-300 flex items-center justify-center ${
                  maintenance ? "translate-x-7" : "translate-x-0"
                }`}
              >
                {loading ? (
                  <Loader2 className="w-3 h-3 text-slate-400 animate-spin" />
                ) : (
                  <Power className={`w-3 h-3 ${maintenance ? "text-red-500" : "text-slate-400"}`} />
                )}
              </span>
            </button>
          </div>

          {/* Status indicator */}
          <div className={`rounded-xl p-4 border ${maintenance ? "bg-red-500/10 border-red-500/20" : "bg-green-500/10 border-green-500/20"}`}>
            <div className="flex items-center gap-2">
              {maintenance ? (
                <AlertTriangle className="w-4 h-4 text-red-400 flex-shrink-0" />
              ) : (
                <CheckCircle className="w-4 h-4 text-green-400 flex-shrink-0" />
              )}
              <p className={`text-sm font-medium ${maintenance ? "text-red-300" : "text-green-300"}`}>
                {maintenance === null
                  ? "Verificando estado..."
                  : maintenance
                  ? "Visitantes ven la página de mantenimiento"
                  : "Sitio completamente operativo"}
              </p>
            </div>
          </div>

          {/* Feedback message */}
          {message && (
            <div className={`flex items-center gap-2 text-sm rounded-lg px-3 py-2 ${
              message.type === "ok"
                ? "text-green-300 bg-green-500/10 border border-green-500/20"
                : "text-red-300 bg-red-500/10 border border-red-500/20"
            }`}>
              {message.type === "ok"
                ? <CheckCircle className="w-4 h-4 flex-shrink-0" />
                : <AlertTriangle className="w-4 h-4 flex-shrink-0" />}
              {message.text}
            </div>
          )}
        </div>

        {/* Info */}
        <p className="text-slate-600 text-xs text-center mt-4">
          Los cambios son instantáneos · Sesión válida 24h
        </p>
      </div>
    </div>
  );
}

// ── Main Admin page ───────────────────────────────────────────────────────────
export default function AdminPage() {
  const [authenticated, setAuthenticated] = useState<boolean | null>(null);

  useEffect(() => {
    // Check if already logged in
    fetch("/api/admin/maintenance", { credentials: "include" })
      .then((r) => setAuthenticated(r.status !== 401))
      .catch(() => setAuthenticated(false));
  }, []);

  if (authenticated === null) {
    return (
      <div className="min-h-screen bg-[#0F2438] flex items-center justify-center">
        <Loader2 className="w-8 h-8 text-[#FFD400] animate-spin" />
      </div>
    );
  }

  if (!authenticated) {
    return <LoginForm onLogin={() => setAuthenticated(true)} />;
  }

  return <Dashboard onLogout={() => setAuthenticated(false)} />;
}
```

